An **array** is a list of values. Use arrays when you have multiple related pieces of data.

```javascript
let colors = ['red', 'green', 'blue'];
let numbers = [10, 20, 30, 40, 50];
let mixed = [1, 'hello', true];
```

Arrays use **square brackets** [ ] and separate items with **commas**.

blocks.code:
let fruits = ['apple', 'banana', 'orange', 'grape'];
let scores = [95, 87, 92, 78, 88];
let isComplete = [true, false, true, true];

console.log(fruits);
console.log(scores);
console.log(isComplete);

let days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'];

console.log('First day:', days[0]);
console.log('Third day:', days[2]);
console.log('Fifth day:', days[4]);

// Get the last item
console.log('Last day:', days[days.length - 1]);

let letters = ['a', 'b', 'c', 'd', 'e'];

console.log('Length:', letters.length);  // 5

// Loop through each item
for (let i = 0; i < letters.length; i++) {
  console.log('Item', i, ':', letters[i]);
}
